import{_ as e,o as a,c as r,a0 as n}from"./chunks/framework.jwovEGr5.js";const o="data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR4nGMAAQAABQABDQottAAAAABJRU5ErkJggg==",g=JSON.parse('{"title":"Premium Features","description":"","frontmatter":{},"headers":[],"relativePath":"subscriptions/premium-features.md","filePath":"subscriptions/premium-features.md"}'),s={name:"subscriptions/premium-features.md"};function i(l,t,d,h,c,u){return a(),r("div",null,[...t[0]||(t[0]=[n('<h1 id="premium-features" tabindex="-1">Premium Features <a class="header-anchor" href="#premium-features" aria-label="Permalink to &quot;Premium Features&quot;">​</a></h1><p>Premium plans unlock extra capabilities on top of the free tier. This page lists every <a href="./../getting-started/glossary.html#premium-feature">premium feature</a> in the app, grouped so you can find what matters to you. Which ones you actually get depends on your <a href="./effective-plan.html">effective plan</a> (or an accepted <a href="./../getting-started/glossary.html#grant">grant</a> that carries them).</p><h2 id="how-a-feature-turns-on" tabindex="-1">How a feature turns on <a class="header-anchor" href="#how-a-feature-turns-on" aria-label="Permalink to &quot;How a feature turns on&quot;">​</a></h2><p>A premium feature becomes active when <strong>either</strong>:</p><ol><li>your effective plan includes it, <strong>or</strong></li><li>your alliance holds an <strong>accepted</strong> kingdom grant whose plan includes it (and the feature is one that can be shared through a grant).</li></ol><p>Until then, the feature appears <strong>locked</strong> — usually as a tab or card labelled &quot;(Premium)&quot; with a prompt to request a subscription. Locked features never show your data; they just show the upgrade prompt.</p><p><img src="'+o+'" alt="Locked vs. active premium area"></p><h2 id="analytics-insight-features" tabindex="-1">Analytics &amp; insight features <a class="header-anchor" href="#analytics-insight-features" aria-label="Permalink to &quot;Analytics &amp; insight features&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>What it unlocks</th></tr></thead><tbody><tr><td><strong>Advanced Analytics</strong></td><td>Deeper dashboards, more comparisons, and finer filters.</td></tr><tr><td><strong>Extra Charts</strong></td><td>Additional charts for events, players, and alliance trends.</td></tr><tr><td><strong>Stage Analytics</strong></td><td>Analysis of staged events, comparing performance between stages.</td></tr><tr><td><strong>Instance Internal Analytics</strong></td><td>Deeper summaries inside a single event instance, including how scores are spread.</td></tr><tr><td><strong>Player Analytics Across Events</strong></td><td>Follow one player across multiple event instances — attendance consistency and score progression over time. <em>(Alliance-focused.)</em></td></tr><tr><td><strong>Custom Analytics Builder</strong></td><td>Build your own tables and charts by scope, event, date range, metric, and grouping. <strong>See the note below.</strong></td></tr></tbody></table><blockquote><p><strong>A note on the Custom Analytics Builder:</strong> the Custom tab is present in the app, but its full unlocked behavior hasn&#39;t been confirmed for this documentation. If your plan includes it, open the Custom tab to see what&#39;s available in your version rather than relying on a fixed description here. Treat it as &quot;available, details may vary.&quot;</p></blockquote><h2 id="recommendation-features" tabindex="-1">Recommendation features <a class="header-anchor" href="#recommendation-features" aria-label="Permalink to &quot;Recommendation features&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>What it unlocks</th></tr></thead><tbody><tr><td><strong>Smart Recommendations</strong></td><td>Rule-based suggestions for cleanup, participation, and follow-up.</td></tr><tr><td><strong>Alliance Recommendations</strong></td><td>Alliance-level follow-up suggestions and watchlists. <em>(Alliance-focused.)</em></td></tr><tr><td><strong>Player Recommendations</strong></td><td>Flags players who need attention, are reward-ready, or need manual review. <em>(Alliance-focused.)</em></td></tr></tbody></table><h2 id="reporting-capacity-features" tabindex="-1">Reporting &amp; capacity features <a class="header-anchor" href="#reporting-capacity-features" aria-label="Permalink to &quot;Reporting &amp; capacity features&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>What it unlocks</th></tr></thead><tbody><tr><td><strong>Premium Report Exports</strong></td><td>Richer export options and premium report packaging.</td></tr><tr><td><strong>Larger Storage</strong></td><td>Bigger screenshot and import storage limits. This one works through your plan&#39;s limits rather than a button you press — a premium plan simply has more room.</td></tr></tbody></table><h2 id="kingdom-to-alliance-sharing" tabindex="-1">Kingdom-to-alliance sharing <a class="header-anchor" href="#kingdom-to-alliance-sharing" aria-label="Permalink to &quot;Kingdom-to-alliance sharing&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>What it unlocks</th></tr></thead><tbody><tr><td><strong>Granted Kingdom Analytics</strong></td><td>Lets an alliance that <strong>accepted a kingdom grant</strong> view aggregate kingdom analytics. This only appears if the accepted grant specifically carries this feature — see the note under <a href="./accept-grant.html">Accept a Premium Offer</a>.</td></tr></tbody></table><h2 id="coming-soon-not-active-yet" tabindex="-1">Coming soon (not active yet) <a class="header-anchor" href="#coming-soon-not-active-yet" aria-label="Permalink to &quot;Coming soon (not active yet)&quot;">​</a></h2><p>These appear in the app but aren&#39;t switched on yet. You may be able to <strong>register interest</strong>, but they don&#39;t unlock anything today:</p><table tabindex="0"><thead><tr><th>Feature</th><th>Status</th></tr></thead><tbody><tr><td><strong>Premium Processing</strong></td><td>Coming soon — improved screenshot/image processing. In the image-processing settings it may show as unavailable, and on the Support &amp; Plans page you can register interest.</td></tr><tr><td><strong>Priority Imports</strong></td><td>Coming soon — future priority handling for imports. Roadmap only for now.</td></tr></tbody></table><h2 id="which-plan-carries-which-features" tabindex="-1">Which plan carries which features <a class="header-anchor" href="#which-plan-carries-which-features" aria-label="Permalink to &quot;Which plan carries which features&quot;">​</a></h2><p>Broadly:</p><ul><li><strong>Premium Alliance</strong> carries the alliance-focused features (player-across-events, alliance and player recommendations) plus the shared analytics and reporting extras.</li><li><strong>Premium Kingdom</strong> carries kingdom-level features plus <strong>Granted Kingdom Analytics</strong>, and lets the King share eligible features with alliances through <a href="./kingdom-grants.html">grants</a>.</li></ul><p>Not every feature can be passed down through a grant. When a King grants premium, the alliance receives only the <strong>shareable</strong> features the grant carries — see <a href="./accept-grant.html">Accept a Premium Offer</a>.</p><p>The exact feature set on <em>your</em> plan is shown in your Subscription &amp; Usage panel and on the <a href="./request-subscription.html">Support &amp; Plans</a> page. That&#39;s the authoritative list for your platform.</p><h2 id="where-to-go-next" tabindex="-1">Where to go next <a class="header-anchor" href="#where-to-go-next" aria-label="Permalink to &quot;Where to go next&quot;">​</a></h2><ul><li><a href="./request-subscription.html">Request a Subscription</a> — ask for a premium plan.</li><li><a href="./kingdom-grants.html">Kingdom Grants</a> / <a href="./accept-grant.html">Accept a Premium Offer</a> — get premium via your King.</li></ul>',26)])])}const p=e(s,[["render",i]]);export{g as __pageData,p as default};
